import UIKit
import Foundation

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    func handleUniversalLink(url: URL) -> Bool {
        guard let components = NSURLComponents(url: url, resolvingAgainstBaseURL: true),
              let token = components.queryItems?.first(where: { $0.name == "token" })?.value else {
            return false
        }
        
        // Navigate to the password reset screen with the token
        let storyboard = UIStoryboard(name: "PasswordReset", bundle: nil)
        let vc = storyboard.instantiateInitialViewController() as! PasswordResetViewController
        vc.token = token
        UIApplication.shared.keyWindow?.rootViewController = vc
        
        return true
    }
}